/// <reference types="@figma/plugin-typings" />
import {
  indexAvailableFonts,
  resolveFont,
  FontName,
  FontResolution,
} from "./font-fallback.js";

/** Cached available-font list + index (populated lazily, once per run). */
let cachedFonts: FontName[] | null = null;
let cachedIndex: ReturnType<typeof indexAvailableFonts> | null = null;
/** Loaded fonts so we never loadFontAsync the same pair twice. */
const loaded = new Set<string>();

function key(f: FontName): string {
  return `${f.family}�${f.style}`;
}

async function ensureIndex(): Promise<void> {
  if (cachedIndex) return;
  const list = await figma.listAvailableFontsAsync();
  cachedFonts = list.map((f) => ({
    family: f.fontName.family,
    style: f.fontName.style,
  }));
  cachedIndex = indexAvailableFonts(cachedFonts);
}

/** For handlers that just need availability info (get_fonts). */
export async function availableFonts(): Promise<FontName[]> {
  await ensureIndex();
  return cachedFonts ?? [];
}

/** Recover the exact-cased FontName from the cached list (for last-resort). */
function exactCase(f: FontName): FontName {
  if (!cachedFonts) return f;
  const match = cachedFonts.find(
    (a) =>
      a.family.toLowerCase() === f.family.toLowerCase() && a.style === f.style,
  );
  return match ?? f;
}

/**
 * Resolve a requested font through the fallback chain and loadFontAsync it.
 * Returns the resolution (with requested/resolved/reason) so handlers can
 * surface substitutions in the response.
 */
export async function loadFontWithFallback(
  requested: FontName,
): Promise<FontResolution> {
  await ensureIndex();
  const res = resolveFont(requested, cachedIndex!);
  const font = exactCase(res.resolvedFont);
  const k = key(font);
  if (!loaded.has(k)) {
    await figma.loadFontAsync(font);
    loaded.add(k);
  }
  return { ...res, resolvedFont: font };
}

/** Load every font already present on a text node (for set_text / edits). */
export async function loadNodeFonts(node: TextNode): Promise<void> {
  const fonts = node.getRangeAllFontNames(0, Math.max(node.characters.length, 1));
  for (const f of fonts) {
    const k = key(f);
    if (!loaded.has(k)) {
      await figma.loadFontAsync(f);
      loaded.add(k);
    }
  }
}

/** Default font used when a TEXT create omits fontFamily. */
export const DEFAULT_FONT: FontName = { family: "Inter", style: "Regular" };
